UPDATE vip_benefit
SET status = 0, start_time = #{startTime}, expire_time = #{expireTime}
WHERE source_order_no = #{orderNo} AND status = 9

UPDATE vip_benefit_card
SET sold_count = sold_count + 1
WHERE vip_card_id = #{vipCardId}

mapper.select:
SELECT b.vip_benefit_id AS vipBenefitId, b.user_id AS userId, b.origin_user_id AS originUserId, b.vip_card_id AS vipCardId, b.source_order_no AS sourceOrderNo, b.store_id AS storeId, b.store_addr_id AS storeAddrId, b.origin_price AS originPrice, b.start_time AS startTime, b.expire_time AS expireTime, b.status, b.transfer_count AS transferCount, b.transferable, b.created_date AS createdDate, c.card_name AS cardName FROM vip_benefit b LEFT JOIN vip_benefit_card c ON b.vip_card_id = c.vip_card_id
b.user_id = #{userId}
AND b.status = #{status}
ORDER BY b.created_date DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(1) FROM vip_benefit

    user_id = #{userId}

        AND status = #{status}
